
(() => {
  function ready(fn){ if(document.readyState === 'loading') document.addEventListener('DOMContentLoaded', fn); else fn(); }
  function addQuickbar(){ const host=document.querySelector('.pro-card .pro-actions')?.closest('.pro-card'); if(!host || host.querySelector('.analysis-open-quickbar')) return; const bar=document.createElement('div'); bar.className='analysis-open-quickbar'; bar.innerHTML='<div class="analysis-open-quickbar__head"><strong>실전 해석 빠른 기준</strong><span>입력 → 상태 확인 → 행동 결정 순서로 보면 가장 빠릅니다.</span></div><div class="analysis-open-quickbar__grid"><div class="analysis-open-quickbar__item"><b>1. 입력</b><p>종목 성격에 맞는 2-way / 3-way 구조부터 맞춥니다.</p></div><div class="analysis-open-quickbar__item"><b>2. 상태</b><p>PASS보다 먼저 주의·재확인 사유가 있는지 봅니다.</p></div><div class="analysis-open-quickbar__item"><b>3. 가격</b><p>마진과 공정배당 차이가 작을수록 해석이 선명합니다.</p></div><div class="analysis-open-quickbar__item"><b>4. 행동</b><p>좋아 보여도 조합보다 단일 판단이 먼저입니다.</p></div></div><div class="analysis-open-actionline"><strong>현재 행동:</strong> 결과가 나오면 아래 브리프와 해석 보조 박스를 함께 보고, 선별 진입 / 보수 확인 / 대기 우선 중 하나로 정리하면 훨씬 빠르게 읽힙니다.</div>'; const firstDivider=host.querySelector('.pro-divider'); if(firstDivider) firstDivider.insertAdjacentElement('beforebegin', bar); else host.appendChild(bar); }
  function syncActionLine(){ const line=document.querySelector('.analysis-open-actionline'); if(!line) return; const stateLabel=(document.querySelector('#sprtBrief .vvip-brief-score .lab')||{}).textContent||''; const scoreText=(document.querySelector('#sprtBrief .vvip-brief-score .n')||{}).textContent||''; const label=stateLabel.trim(); const score=parseFloat(String(scoreText).replace(/[^0-9.]/g,'')); let message='결과가 나오면 브리프와 상태 라벨을 함께 확인하세요.'; if(label==='안정' && score >= 85) message='상대적으로 선별 진입을 검토할 수 있는 구간입니다. 단, 가격이 과열되지 않았는지 마지막으로 확인하는 편이 좋습니다.'; else if(label==='양호' || score >= 70) message='방향보다 가격 메리트와 재확인 포인트를 먼저 보는 보수 해석이 좋습니다.'; else if(label==='재확인') message='현재는 추가 확인이 먼저인 구간입니다. 급하게 결론 내리기보다 대기 후 다시 계산하는 편이 좋습니다.'; else if(label==='주의' || (Number.isFinite(score) && score < 55)) message='대기 우선 구간입니다. 조합 확대나 추격 해석은 특히 피하는 편이 좋습니다.'; line.innerHTML=`<strong>현재 행동:</strong> ${message}`; }
  function addMobileBar(){ if(document.querySelector('.analysis-mobile-bar')) return; const apply=document.getElementById('btnApply'); const clear=document.getElementById('btnClear'); const copy=document.getElementById('btnCopySummary'); if(!apply||!clear||!copy) return; const bar=document.createElement('div'); bar.className='analysis-mobile-bar'; bar.innerHTML='<button class="is-primary" type="button">분석</button><button type="button">초기화</button><button type="button">브리프 복사</button>'; const buttons=bar.querySelectorAll('button'); buttons[0].addEventListener('click',()=>apply.click()); buttons[1].addEventListener('click',()=>clear.click()); buttons[2].addEventListener('click',()=>copy.click()); document.body.appendChild(bar); }
  function guardInputs(){ document.querySelectorAll('.pro-field input[type="number"]').forEach((input)=>{ input.addEventListener('input',()=>{ const min=input.getAttribute('min'); if(min !== null && input.value !== '' && Number(input.value) < Number(min)) input.value=min; }); }); }
  ready(() => { addQuickbar(); addMobileBar(); guardInputs(); syncActionLine(); const target=document.getElementById('proResult') || document.body; const mo=new MutationObserver(()=>syncActionLine()); mo.observe(target,{ childList:true, subtree:true, characterData:true }); });
})();
